package io.fletchly.comparator.port.out

import io.fletchly.comparator.model.message.Message
import io.fletchly.comparator.model.message.ToolCall

/**
 * Represents a port for executing tools in the system.
 */
interface ToolPort {
    /**
     * Executes a tool call and returns the resulting tool message.
     *
     * @param toolCall The tool call to be executed, including the tool name and its arguments.
     * @return [Message.Tool] object representing the response or output generated by the executed tool.
     */
    suspend fun execute(toolCall: ToolCall): Message.Tool
}